// Habis Free Shapenya cik

public sealed interface Answer permits
	MultipleChoiceAnswer,
	FillBlankAnswer,
	DragAndDropAnswer {}
public record MultipleChoiceAnswer(Set<String> selectedOptionIds) implements Answer {}
public record FillBlankAnswer(List<String> filledValues) implements Answer {}
// List because a prompt can have multiple blanks: "__ is the capital of __"
public record DragAndDropAnswer(Map<String, String> pairings) implements Answer {}
